import React, { useEffect, useState } from "react";
import axios from "axios";
import "./App.css";

const API = "http://localhost:5000";

const DRIVE_LINK =
  "https://drive.google.com/file/d/1LKc-w9Ggd5I1eZ3t7Wvm9psU-4ITxHxr/view?usp=sharing";

const DEFAULT_TEMPLATES = [
  { id: "formal", name: "Formal", customNote: "I am excited to apply for this opportunity and would welcome the chance to discuss how my experience aligns with your team." },
  { id: "startup", name: "Startup Friendly", customNote: "I’m thrilled about the chance to contribute to your team and build impactful products with a fast-moving group." },
  { id: "referral", name: "Referral", customNote: "I am reaching out with strong interest in this role and would be happy to share more about my background and relevant experience." },
];

function loadTemplates() {
  try { return JSON.parse(localStorage.getItem("emailTemplates") || "null") || DEFAULT_TEMPLATES; } catch { return DEFAULT_TEMPLATES; }
}

// ─── Sent Applications Log (in-memory) ───────────────────────────────────────
function SentLog({ log }) {
  if (!log.length) return null;
  return (
    <div className="sent-log">
      <h3 className="log-title">📋 Sent Applications</h3>
      <div className="log-list">
        {log.map((entry, i) => (
          <div key={i} className="log-item">
            <div className="log-main">
              <span className="log-company">{entry.company}</span>
              {entry.role && <span className="log-role">{entry.role}</span>}
              <span className={`log-badge log-badge-${entry.type}`}>
                {entry.type === "application" ? "Applied" : "Follow-up"}
              </span>
            </div>
            <div className="log-meta">
              <span>{entry.email}</span>
              <span>{entry.time}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── Application Form ─────────────────────────────────────────────────────────
function ApplicationForm({ onSent, templates, applyTemplate, saveTemplate }) {
  const [form, setForm] = useState({ hrEmail: "", hrName: "", company: "", role: "", customNote: "" });
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);
  const [mode, setMode] = useState("now");
  const [scheduledDate, setScheduledDate] = useState("");

  const handle = (e) => {
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));
    if (status) setStatus(null);
  };

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus(null);
    try {
      if (mode === "schedule") {
        if (!scheduledDate) throw new Error("Please choose a date for scheduling.");
        const res = await axios.post(`${API}/api/schedule-email`, { ...form, scheduledDate });
        setStatus({ type: "success", text: res.data.message });
      } else {
        const res = await axios.post(`${API}/api/send-application`, form);
        setStatus({ type: "success", text: res.data.message });
        onSent({
          type: "application",
          company: form.company,
          role: form.role,
          email: form.hrEmail,
          time: new Date().toLocaleString(),
          messageId: res.data.messageId,
          subject: form.role ? `Application for ${form.role} Position — Anav Bansal` : "Job Application — Anav Bansal",
          hrName: form.hrName,
          hrEmail: form.hrEmail,
        });
      }
      setForm({ hrEmail: "", hrName: "", company: "", role: "", customNote: "" });
      setScheduledDate("");
    } catch (err) {
      setStatus({
        type: "error",
        text: err.response?.data?.message || "Failed to send. Check backend.",
      });
    } finally {
      setLoading(false);
    }
  };

  const valid = form.hrEmail && form.company;

  return (
    <form className="mailer-form" onSubmit={submit} noValidate>
      <div className="form-group">
        <label className="form-label" htmlFor="templateSelect">Templates</label>
        <select className="form-input" id="templateSelect" onChange={(e) => applyTemplate(e.target.value)} defaultValue="">
          <option value="">— Choose a template —</option>
          {templates.map((t) => <option key={t.id} value={t.id}>{t.name}</option>)}
        </select>
        <button type="button" className="btn-ghost" onClick={() => { const name = window.prompt("Template name", "My Template"); if (!name) return; saveTemplate(name, form); }}>Save as Template</button>
      </div>
      <div className="form-group">
