// ─── Follow-up Form ───────────────────────────────────────────────────────────
function FollowUpForm({ sentLog, onSent }) {
  const [mode, setMode] = useState("select"); // select | manual
  const [selectedIdx, setSelectedIdx] = useState("");
  const [form, setForm] = useState({
    hrEmail: "", hrName: "", company: "", role: "",
    originalDate: "", customNote: "",
    originalMessageId: "", originalSubject: "",
  });
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);

  const handle = (e) => {
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));
    if (status) setStatus(null);
  };

  const selectApplication = (idx) => {
    setSelectedIdx(idx);
    if (idx === "") return;
    const entry = sentLog[parseInt(idx)];
    setForm({
      hrEmail: entry.hrEmail || "",
      hrName: entry.hrName || "",
      company: entry.company || "",
      role: entry.role || "",
      originalDate: entry.time || "",
      customNote: "",
      originalMessageId: entry.messageId || "",
      originalSubject: entry.subject || "",
    });
    if (status) setStatus(null);
  };

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus(null);
    try {
      const res = await axios.post(`${API}/api/send-followup`, form);
      setStatus({ type: "success", text: res.data.message });
      onSent({
        type: "followup",
        company: form.company,
        role: form.role,
        email: form.hrEmail,
        time: new Date().toLocaleString(),
        messageId: res.data.messageId,
        subject: form.originalSubject,
        hrName: form.hrName,
        hrEmail: form.hrEmail,
      });
      setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" });
      setSelectedIdx("");
    } catch (err) {
      setStatus({ type: "error", text: err.response?.data?.message || "Failed to send." });
    } finally {
      setLoading(false);
    }
  };

  const valid = form.hrEmail && form.company;
  const appliedEntries = sentLog.filter((e) => e.type === "application");

  return (
    <form className="mailer-form" onSubmit={submit} noValidate>

      {/* Quick-fill from sent applications */}
      {appliedEntries.length > 0 && (
        <div className="form-group">
          <label className="form-label" htmlFor="selectApp">
            <span className="lbadge lbadge-green">Quick Fill</span>
            Select from sent applications
          </label>
          <select
            id="selectApp" className="form-input form-select"
            value={selectedIdx} onChange={(e) => selectApplication(e.target.value)}
            disabled={loading}
          >
            <option value="">— Choose a previous application —</option>
            {sentLog.map((e, i) =>
              e.type === "application" ? (
                <option key={i} value={i}>
                  {e.company}{e.role ? ` · ${e.role}` : ""} ({e.email}) — {e.time}
                </option>
              ) : null
            )}
          </select>
        </div>
      )}

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrEmail">
            <span className="lbadge">Required</span> HR Email
          </label>
          <input id="fu-hrEmail" name="hrEmail" type="email" value={form.hrEmail}
            onChange={handle} placeholder="recruiter@company.com"
            className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrName">
            <span className="lbadge lbadge-opt">Optional</span> HR Name
          </label>
          <input id="fu-hrName" name="hrName" type="text" value={form.hrName}
            onChange={handle} placeholder="e.g. Priya Sharma"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-company">
            <span className="lbadge">Required</span> Company
          </label>
          <input id="fu-company" name="company" type="text" value={form.company}
            onChange={handle} placeholder="Company Name"
            className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-role">
            <span className="lbadge lbadge-opt">Optional</span> Role
          </label>
          <input id="fu-role" name="role" type="text" value={form.role}
            onChange={handle} placeholder="e.g. Senior Full Stack Developer"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-date">
            <span className="lbadge lbadge-opt">Optional</span> Original Application Date
          </label>
          <input id="fu-date" name="originalDate" type="text" value={form.originalDate}
            onChange={handle} placeholder="e.g. 25 May 2026"
            className="form-input" disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-msgid">
            <span className="lbadge lbadge-opt">Optional</span> Original Message ID
            <span className="label-hint">Auto-filled if you used Quick Fill — enables email threading</span>
          </label>
          <input id="fu-msgid" name="originalMessageId" type="text" value={form.originalMessageId}
            onChange={handle} placeholder="<msgid@gmail.com>"
            className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-group">
        <label className="form-label" htmlFor="fu-note">
          <span className="lbadge lbadge-opt">Optional</span> Custom Note
        </label>
        <textarea id="fu-note" name="customNote" value={form.customNote}
          onChange={handle}
          placeholder="e.g. I wanted to reiterate my excitement about this opportunity. I recently..."
          className="form-textarea" rows={3} disabled={loading} />
      </div>

      {/* Thread info */}
      {form.originalMessageId && (
        <div className="thread-notice">
          <span className="thread-icon">🧵</span>
          <span>This follow-up will be sent <strong>in the same email thread</strong> as the original application.</span>
        </div>
      )}

      {status && (
        <div className={`alert alert-${status.type}`} role="alert">
          <span className="alert-icon">{status.type === "success" ? "✓" : "✕"}</span>
          <span>{status.text}</span>
        </div>
      )}

      <div className="form-footer">
        <button type="submit" className={`btn-followup ${loading ? "loading" : ""}`} disabled={loading || !valid}>
          {loading ? <><span className="spinner" /> Sending Follow-up…</> : <><span className="btn-arrow">↑</span> Send Follow-up</>}
        </button>
        <button type="button" className="btn-ghost" disabled={loading}
          onClick={() => { setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" }); setSelectedIdx(""); setStatus(null); }}>
          Clear
        </button>
      </div>
    </form>
  );
}

function BulkSendPanel() {
  const [text, setText] = useState("");
  const [result, setResult] = useState(null);
  const [running, setRunning] = useState(false);
  const preview = text.split("\n").filter(Boolean).map((line) => {
    const [hrEmail = "", hrName = "", company = "", role = ""] = line.split(",");
    return { hrEmail: hrEmail.trim(), hrName: hrName?.trim() || "", company: company?.trim() || "", role: role?.trim() || "" };
  });
  const sendBulk = async () => {
    setRunning(true); setResult(null);
    try { const res = await axios.post(`${API}/api/bulk-send`, { emailList: preview, customNote: "", attachResume: true }); setResult(res.data); }
    catch (e) { setResult({ success: false, message: e.response?.data?.message || e.message }); }
    finally { setRunning(false); }
  };
  return <div className="mailer-form"><div className="form-group"><label className="form-label">Bulk Email List</label><textarea className="form-textarea" rows={8} value={text} onChange={(e) => setText(e.target.value)} placeholder="hr@google.com, Priya Sharma, Google, Senior Developer" /></div>{preview.length > 0 && <div className="preview-card"><p className="preview-title">Preview</p>{preview.map((item, idx) => <p key={idx} className="preview-line">{idx + 1}. {item.hrEmail || "—"} · {item.company || "—"} · {item.role || "—"}</p>)}</div>}<button type="button" className="btn-primary" disabled={running || preview.length === 0} onClick={sendBulk}>{running ? "Sending..." : "Send Bulk"}</button>{result && <div className={`alert ${result.success ? "alert-success" : "alert-error"}`}>{result.success ? `Sent ${result.sent}/${result.total}.` : result.message}</div>}</div>;
}

function InboxPanel() {
  const [messages, setMessages] = useState([]);
  const connect = () => { window.location.href = `${API}/api/gmail/auth`; };
  useEffect(() => { axios.get(`${API}/api/gmail/inbox`).then((res) => { if (res.data.success) setMessages(res.data.messages || []); }).catch(() => {}); }, []);
  return <div className="mailer-form"><button type="button" className="btn-primary" onClick={connect}>Connect Gmail</button>{messages.length > 0 ? <div className="preview-card">{messages.map((m) => <div key={m.id} className="log-item"><div className="log-main"><strong>{m.subject}</strong><span className="log-badge">{m.isRead ? "Read" : "Unread"}</span></div><div className="log-meta"><span>{m.from}</span><span>{m.date}</span></div><p className="preview-line">{m.snippet}</p></div>)}</div> : <p className="preview-line">Connect Gmail to list recent inbox items.</p>}</div>;
}

function RemindersPanel() {
  const [reminders, setReminders] = useState([]);
  useEffect(() => { setReminders(JSON.parse(localStorage.getItem("jobMailerReminders") || "[]")); }, []);
  const remove = (id) => { const updated = reminders.filter((x) => x.id !== id); localStorage.setItem("jobMailerReminders", JSON.stringify(updated)); setReminders(updated); };
  const snooze = (id) => { const updated = reminders.map((x) => x.id === id ? { ...x, reminderDate: new Date(new Date(x.reminderDate).getTime() + 2 * 86400000).toISOString().slice(0, 10), notified: false } : x); localStorage.setItem("jobMailerReminders", JSON.stringify(updated)); setReminders(updated); };
  return <div className="mailer-form"><div className="preview-card"><p className="preview-title">Reminders</p>{reminders.length ? reminders.map((item) => <div key={item.id} className="log-item"><div className="log-main"><strong>{item.company}</strong><span className="log-badge">{item.reminderDate}</span></div><p className="preview-line">{item.note || "No note"}</p><div className="form-footer"><button type="button" className="btn-ghost" onClick={() => snooze(item.id)}>Snooze +2d</button><button type="button" className="btn-ghost" onClick={() => remove(item.id)}>Delete</button></div></div>) : <p className="preview-line">No reminders yet.</p>}</div></div>;
}

function ScheduledPanel() {
  const [jobs, setJobs] = useState([]);
  useEffect(() => { axios.get(`${API}/api/scheduled-emails`).then((res) => setJobs(res.data.jobs || [])).catch(() => setJobs([])); }, []);
  const remove = async (jobId) => { await axios.delete(`${API}/api/scheduled-emails/${jobId}`); setJobs((p) => p.filter((j) => j.jobId !== jobId)); };
  return <div className="mailer-form"><div className="preview-card"><p className="preview-title">Scheduled Emails</p>{jobs.length ? jobs.map((job) => <div key={job.jobId} className="log-item"><div className="log-main"><strong>{job.emailData.company}</strong><span className="log-badge">{job.status}</span></div><div className="log-meta"><span>{job.emailData.hrEmail}</span><span>{new Date(job.scheduledTime).toLocaleString()}</span></div><button type="button" className="btn-ghost" onClick={() => remove(job.jobId)}>Cancel</button></div>) : <p className="preview-line">No scheduled emails yet.</p>}</div></div>;
}

// ─── Main App ─────────────────────────────────────────────────────────────────
export default function App() {
  const [tab, setTab] = useState("apply");
  const [sentLog, setSentLog] = useState([]);
  const [trackingRecords, setTrackingRecords] = useState([]);
  const [templates, setTemplates] = useState(loadTemplates());

  useEffect(() => {
    axios.get(`${API}/api/track/status`).then((res) => setTrackingRecords(res.data.records || [])).catch(() => {});
    const timer = setInterval(() => axios.get(`${API}/api/track/status`).then((res) => setTrackingRecords(res.data.records || [])).catch(() => {}), 30000);
    return () => clearInterval(timer);
  }, []);

  const addToLog = (entry) => setSentLog((p) => [entry, ...p]);
  const applyTemplate = (id) => {
    const template = templates.find((t) => t.id === id);
    if (!template) return;
    // template prefill is reflected in form state on next interaction
    alert(`Template "${template.name}" loaded. You can now apply its note in the form.`);
  };
  const saveTemplate = (name, form) => { const next = [...templates, { id: Date.now().toString(), name, customNote: form.customNote }]; setTemplates(next); localStorage.setItem("emailTemplates", JSON.stringify(next)); alert("Template saved to localStorage."); };

  return (
    <div className="app">
      <div className="bg-mesh" aria-hidden="true" />

      <div className="container">
        {/* Profile Header */}
        <header className="profile-header">
          <div className="profile-avatar">AB</div>
          <div className="profile-info">
            <h1 className="profile-name">Anav Bansal</h1>
            <p className="profile-title">Senior Full Stack Developer · Node.js · Angular · AWS · CTI/Telephony</p>
            <div className="profile-links">
              <a href="mailto:anavbansal06@gmail.com" className="plink">✉ anavbansal06@gmail.com</a>
              <a href="tel:+917827855635" className="plink">📞 +91 7827855635</a>
              <a href="https://linkedin.com/in/anavbansal-51b191162" target="_blank" rel="noreferrer" className="plink">🔗 LinkedIn</a>
              <a href={DRIVE_LINK} target="_blank" rel="noreferrer" className="plink plink-resume">📄 Resume (Drive)</a>
            </div>
          </div>
          <div className="profile-exp">
            <span className="exp-num">4.7+</span>
            <span className="exp-label">Years Exp.</span>
          </div>
        </header>

        {/* Tabs */}
        <div className="tabs">
          <button className={`tab ${tab === "apply" ? "tab-active" : ""}`} onClick={() => setTab("apply")}><span className="tab-icon">✉</span>Send Application</button>
          <button className={`tab ${tab === "followup" ? "tab-active tab-followup" : ""}`} onClick={() => setTab("followup")}><span className="tab-icon">🔁</span>Send Follow-up</button>
          <button className={`tab ${tab === "bulk" ? "tab-active" : ""}`} onClick={() => setTab("bulk")}><span className="tab-icon">📦</span>Bulk Send</button>
          <button className={`tab ${tab === "inbox" ? "tab-active" : ""}`} onClick={() => setTab("inbox")}><span className="tab-icon">📥</span>Inbox</button>
        </div>

        {/* Form Card */}
        <div className="card">
          {tab === "apply" ? (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Job Application Email</h2>
                  <p className="card-subtitle">
                    Sends a professional application with your resume attached + Google Drive link
                  </p>
                </div>
                <div className="attachment-badge">
                  <span>📎</span> Resume Auto-Attached
                </div>
              </div>
              <ApplicationForm onSent={addToLog} templates={templates} applyTemplate={applyTemplate} saveTemplate={saveTemplate} />
            </>
          ) : tab === "followup" ? (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Follow-up Email</h2>
                  <p className="card-subtitle">Sends a follow-up on the same thread as your original application</p>
                </div>
                <div className="attachment-badge attachment-badge-green"><span>🧵</span> Thread Reply</div>
              </div>
              <FollowUpForm sentLog={sentLog} onSent={addToLog} />
            </>
          ) : tab === "bulk" ? (
            <>
              <div className="card-header"><div><h2 className="card-title">Bulk Send</h2><p className="card-subtitle">Paste a list of recipients and send sequentially.</p></div><div className="attachment-badge"><span>📦</span> Bulk Mailer</div></div>
              <BulkSendPanel />
            </>
          ) : (
            <>
              <div className="card-header"><div><h2 className="card-title">Inbox Reader</h2><p className="card-subtitle">Connect Gmail and preview recent threads.</p></div><div className="attachment-badge"><span>📥</span> Gmail API</div></div>
              <InboxPanel />
